/**
 * 화면 초기화
 */

scwin.globalVal = {
    CREATE_AUTH : "C",
    RETRIEVE_AUTH : "R",
    UPDATE_AUTH : "U",
    DELETE_AUTH : "D",
    PRINT_AUTH : "P",
    EXCEL_AUTH : "X"

}

scwin.closeArr = [];
scwin.closeFlag = false;

scwin.wrkPlCd = "";
scwin.eqCd = "";
scwin.lobranCd  = "";


scwin.onpageload = async function () {
    document.onkeydown = scwin.cfOnKeyDown;

    let userId = WebSquare.localStorage.getItem("userId");

    if(!userId) {
        location.href = "/";
    };

    let userClsCd = WebSquare.localStorage.getItem("userClsCd")
    let coCd = WebSquare.localStorage.getItem("coCd");
    let lobranCd = WebSquare.localStorage.getItem("lobranCd");

    if(coCd === "000"){
        dma_allMenu.set("coCd", "tobe");
    }
    else if(coCd === ""){
        // 20260212: 오류발생해서 임시주석 dma_allMenu.set("coCd", "memObj.coCd");
        dma_allMenu.set("coCd", "");
    }
    else if(coCd === "017"){
        dma_allMenu.set("coCd", "tobe017");
    }
    else{
        dma_allMenu.set("coCd", "tobeCompany");
    }

    dma_allMenu.set("userId", userId);
    $c.sbm.execute(sbm_allMenuList); // 전체 메뉴정보 가져오기

    dma_mem.set("userId", userId);
    let e = await $c.sbm.execute(sbm_getMemInfo); // 회원정보가져오기
    if(e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        dma_memInfo.setJSON(e.responseJSON.GAUCE[0]);
        if(e.responseJSON.GAUCE[0].basisMenuClsCd == "02") {
            wfm_side.getWindow().tac_tabControl1.setSelectedTabIndex(1); // 마이메뉴 탭
        }

        // 로컬스토리지를 지운다
        [
            "coClsCd", "privAdmin", "coCd","sysCd", "userHomeClsCd", "userClsCd", "userId",
            "userNm", "empNo", "email", "lobranCd"
        ].forEach(function (key) {
            WebSquare.localStorage.removeItem(key);
        });

        // WebSquare.localStorage.removeItem("coClsCd");
        // WebSquare.localStorage.removeItem("privAdmin");
        // WebSquare.localStorage.removeItem("coCd");
        // WebSquare.localStorage.removeItem("sysCd");
        // WebSquare.localStorage.removeItem("userHomeClsCd");
        // WebSquare.localStorage.removeItem("userClsCd");
        // WebSquare.localStorage.removeItem("userId");
        // WebSquare.localStorage.removeItem("lobranCd");

        wfm_header.getWindow().txt_userNm.setValue(dma_memInfo.get("userNm"));
        wfm_header.getWindow().txt_lastDt.setValue(dma_memInfo.get("finalConDtm"));

        dma_memInfo.set("hdofficeIdx", dma_memInfo.get("hdofficeIdx") + ".0")
        dma_memInfo.set("bhofficeIdx", dma_memInfo.get("bhofficeIdx") + ".0")
        dma_memInfo.set("officeIdx", dma_memInfo.get("officeIdx") + ".0")

    }
    let darkYn = $c.data.getMemInfo("darkmodeYn");
    if(darkYn == "1") {
        $("body").addClass("dark");
    }
// debugger;

    $c.sbm.execute(sbm_holiday); // 공휴일 정보가져오기
}

scwin.resetUserAuth = function() {
    scwin.globalVal.CREATE_AUTH = false;
    scwin.globalVal.RETRIEVE_AUTH = false;
    scwin.globalVal.UPDATE_AUTH = false;
    scwin.globalVal.DELETE_AUTH = false;
    scwin.globalVal.PRINT_AUTH = false;
    scwin.globalVal.EXCEL_AUTH = false;
};

scwin.setFullUserAuth = function() {
    scwin.globalVal.CREATE_AUTH = "C";
    scwin.globalVal.RETRIEVE_AUTH = "R";
    scwin.globalVal.UPDATE_AUTH = "U";
    scwin.globalVal.DELETE_AUTH = "D";
    scwin.globalVal.PRINT_AUTH = "P";
    scwin.globalVal.EXCEL_AUTH = "X";
};

scwin.getCurrentAuthUserId = function() {
    let userId = "";

    try {
        if ($p.top().dma_mem) {
            userId = $p.top().dma_mem.get("userId") || "";
        }
    } catch (e) {}

    try {
        if (!userId) {
            userId = WebSquare.localStorage.getItem("userId") || "";
        }
    } catch (e) {}

    return (userId || "").toLowerCase();
};

scwin.getCurrentAuthPgmId = function() {
    let pgmId = "";

    try {
        if ($p.top().dma_mem) {
            pgmId = $p.top().dma_mem.get("pgmId") || "";
        }
    } catch (e) {}

    try {
        if (!pgmId && typeof $p.getAllParameter === "function") {
            const allParam = $p.getAllParameter();
            if (allParam && allParam.paramData && allParam.paramData.menuInfo && allParam.paramData.menuInfo.pgmId) {
                pgmId = allParam.paramData.menuInfo.pgmId;
            }
        }
    } catch (e) {}

    return (pgmId || "").replace(/\.xml$/i, ".jsp");
};

scwin.getCurrentAuthSysCd = function() {
    let sysCd = "";
    const pgmId = scwin.getCurrentAuthPgmId();
    let currentMenuId = "";

    if ((pgmId || "").indexOf("zz_620_01_") === 0) {
        return "CM";
    }
    if (!currentMenuId && currentMenuId.indexOf("n") > -1) {
        menuSysCd = "NC";
    }
    try {
        if ($p.top().dma_mem) {
            sysCd = $p.top().dma_mem.get("authSysCd") || "";
            currentMenuId = $p.top().dma_mem.get("authMenuId") || "";
        }
    } catch (e) {}

    try {
        if (typeof $p.getAllParameter === "function") {
            const allParam = $p.getAllParameter();
            if (allParam && allParam.paramData && allParam.paramData.menuInfo) {
                currentMenuId = currentMenuId || allParam.paramData.menuInfo.menuId || "";
                if (!sysCd && allParam.paramData.menuInfo.sysCd) {
                    sysCd = allParam.paramData.menuInfo.sysCd;
                }
            }
        }
    } catch (e) {}

    try {
        if (!sysCd && currentMenuId && typeof ds_allMenuList !== "undefined") {
            const matchedMenuById = ds_allMenuList.getMatchedJSON("menuId", currentMenuId, false);
            if (matchedMenuById && matchedMenuById[0] && matchedMenuById[0].sysCd) {
                sysCd = matchedMenuById[0].sysCd;
            }
        }
    } catch (e) {}

    try {
        if (!sysCd && pgmId && typeof ds_allMenuList !== "undefined") {
            const matchedMenu = ds_allMenuList.getMatchedJSON("actPgmId", pgmId, false);
            if (matchedMenu && matchedMenu[0] && matchedMenu[0].sysCd) {
                sysCd = matchedMenu[0].sysCd;
            }
        }
    } catch (e) {}

    try {
        if (!sysCd && $p.top().wfm_header && $p.top().wfm_header.getWindow) {
            const headerScope = $p.top().wfm_header.getWindow();
            if (headerScope && headerScope.dma_userParam) {
                sysCd = headerScope.dma_userParam.get("sysCd") || "";
            }
        }
    } catch (e) {}

    try {
        if (!sysCd) {
            sysCd = WebSquare.localStorage.getItem("sysCd") || "";
        }
    } catch (e) {}

    return (sysCd || "").toUpperCase();
};

scwin.isNcallContext = function() {
    let sysCd = "";

    try {
        if ($p.top().wfm_header && $p.top().wfm_header.getWindow) {
            const headerScope = $p.top().wfm_header.getWindow();
            if (headerScope && headerScope.dma_userParam) {
                sysCd = headerScope.dma_userParam.get("sysCd") || "";
            }
        }
    } catch (e) {}

    try {
        if (!sysCd) {
            sysCd = WebSquare.localStorage.getItem("sysCd") || "";
        }
    } catch (e) {}

    return (sysCd || "").toUpperCase() === "NC";
};

scwin.getUserAuthActions = function() {
    const currentAuthSysCd = scwin.getCurrentAuthSysCd();
    const actions = currentAuthSysCd === "NC"
        ? [
            "/ncall.cm.bc.comnmgnt.privmgnt.RetrieveUserEachScreenPrivilegeCMD.do"
        ]
        : [
            "/cm.bc.comnmgnt.privmgnt.RetrieveUserEachScreenPrivilegeCMD.do"
        ];

    return actions.filter(function (action, index, arr) {
        return !!action && arr.indexOf(action) === index;
    });
};


scwin.isTemporaryAuthBypass = function() {
    return false;
};

scwin.isAuthBypassContext = function() {
    let authBypassYn = "";
    const pgmId = scwin.getCurrentAuthPgmId().toLowerCase();
    const isUserSettingBypassPage = pgmId.indexOf("zz_620_01_00b") === 0
        || pgmId.indexOf("zz_620_01_02b") === 0
        || pgmId.indexOf("zz_620_01_03b") === 0
        || pgmId.indexOf("zz_620_01_04b") === 0
        || pgmId.indexOf("zz_620_01_04b_01") === 0
        || pgmId.indexOf("zz_620_01_04b_02") === 0
        || pgmId.indexOf("zz_620_01_06b") === 0;

    try {
        if ($p.top().dma_mem) {
            authBypassYn = $p.top().dma_mem.get("authBypassYn") || "";
        }
    } catch (e) {}

    try {
        if (!authBypassYn && typeof $p.getAllParameter === "function") {
            const allParam = $p.getAllParameter();
            if (allParam && allParam.paramData && allParam.paramData.menuInfo) {
                authBypassYn = allParam.paramData.menuInfo.authBypassYn || "";
            }
        }
    } catch (e) {}

    return authBypassYn === "Y" || isUserSettingBypassPage;
};

scwin.applyUserAuthRow = function (authRow) {
    if (!authRow) {
        scwin.resetUserAuth();
        return false;
    }

    scwin.globalVal.CREATE_AUTH = authRow.insYn == "1" ? "C" : false;
    scwin.globalVal.RETRIEVE_AUTH = authRow.qryYn == "1" ? "R" : false;
    scwin.globalVal.UPDATE_AUTH = authRow.modYn == "1" ? "U" : false;
    scwin.globalVal.DELETE_AUTH = authRow.delYn == "1" ? "D" : false;
    scwin.globalVal.PRINT_AUTH = authRow.prtnYn == "1" ? "P" : false;
    scwin.globalVal.EXCEL_AUTH = authRow.xlsDwnldYn == "1" ? "X" : false;
    return authRow.qryYn == "1";
};

scwin.mergeUserAuthRows = function (authRows) {
    const validRows = (authRows || []).filter(function (row) {
        return !!row;
    });

    if (validRows.length === 0) {
        return null;
    }

    return validRows.reduce(function (merged, row) {
        merged.userId = merged.userId || row.userId || "";
        merged.pgmId = merged.pgmId || row.pgmId || "";
        merged.pgmNm = merged.pgmNm || row.pgmNm || "";
        merged.insYn = (merged.insYn == "1" || row.insYn == "1") ? "1" : "0";
        merged.qryYn = (merged.qryYn == "1" || row.qryYn == "1") ? "1" : "0";
        merged.modYn = (merged.modYn == "1" || row.modYn == "1") ? "1" : "0";
        merged.delYn = (merged.delYn == "1" || row.delYn == "1") ? "1" : "0";
        merged.prtnYn = (merged.prtnYn == "1" || row.prtnYn == "1") ? "1" : "0";
        merged.xlsDwnldYn = (merged.xlsDwnldYn == "1" || row.xlsDwnldYn == "1") ? "1" : "0";
        return merged;
    }, {
        userId : "",
        pgmId : "",
        pgmNm : "",
        insYn : "0",
        qryYn : "0",
        modYn : "0",
        delYn : "0",
        prtnYn : "0",
        xlsDwnldYn : "0"
    });
};

scwin.executeUserAuthAction = function (action) {
    $c.sbm.setAction($p, sbm_userAuth, action);

    return $c.sbm.execute(sbm_userAuth).then(function (e) {
        if (e && e.responseJSON && e.responseJSON.resultDataSet && e.responseJSON.resultDataSet[0]) {
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC" && typeof e.responseJSON.OUT_DS1[0] !== "undefined") {
                return e.responseJSON.OUT_DS1[0];
            }
        }
        return null;
    }).catch(function () {
        return null;
    });
};

scwin.executeUserAuthActions = function (actions) {
    const validActions = (actions || []).filter(function (action, index, arr) {
        return !!action && arr.indexOf(action) === index;
    });

    return validActions.reduce(function (promise, action) {
        return promise.then(function (rows) {
            return scwin.executeUserAuthAction(action).then(function (row) {
                rows.push(row);
                return rows;
            });
        });
    }, Promise.resolve([]));
};

scwin.setUserAuth = function() {
    if (scwin.isTemporaryAuthBypass() || scwin.isAuthBypassContext()) {
        scwin.setFullUserAuth();
        return Promise.resolve(true);
    }

    const authActions = scwin.getUserAuthActions();

    var promise = scwin.executeUserAuthActions(authActions).then(function(authRows) {
        return scwin.mergeUserAuthRows(authRows);
    }).then(function(authRow) {
        return scwin.applyUserAuthRow(authRow);
    }).catch(function() {
        scwin.resetUserAuth();
        return false;
    });
    return promise;
};

//  AS-Is 함수 키보드 입력 중 onKeyDown 이벤트에 대한 모든 처리를 담당<br>
scwin.cfOnKeyDown = function() {
    if (window.event && window.event.keyCode == 8) {
        if (window.event.srcElement.tagName.toUpperCase() == "BODY"
         || window.event.srcElement.tagName.toUpperCase() == "TD") {
            window.event.cancelBubble = true;
            window.event.returnValue = false;
            return false;
        } else {
        	return true;
        }
    }
}

scwin.tac_layout_onbeforetabclose = function (tabID, idx) {
    const tabFrame = this.getFrame(idx);
    return scwin.closeBeforePage(tabFrame);
};

/**
 * @method
 * @name closeBeforePage
 * @description 화면이 닫히 전에 변경된 데이터가 있는지 검사한다.
 * @param {string} frameObj 닫으려는 화면의 wframe obj
 * @hidden N
 * @exception 
 * @example main.closeBeforePage(frameObj)
 */
scwin.closeBeforePage =  function (frameObj) {
    //if (checkBeforeCloseModified(frameObj)) {
    if(!scwin.closeFlag) {
        let ret = confirm("창을 닫으면 진행 중이던 작업이 종료됩니다.\n창을 닫으시겠습니까?");
        if (ret) {
            return true;
        } else {
            return false;
        }
    } else {
        return true;
    }
    // } else {
    //     return true;
    // }

    function checkBeforeCloseModified(frameObj) {//debugger;
        const changeCheckMainFrame = $c.data.getChangeCheckedMainFrame(frameObj.scope.$p);
        let objArr = $c.util.getChildren(frameObj, {
            includePlugin: "gridView",
            recursive: true
        });

        for(let idx in objArr) {
            let dltStr = objArr[idx].getDataList();
            if(!$c.util.isEmpty(dltStr)) {
                let dlt = $c.gus.object(dltStr);
                if(!$c.util.isEmpty(dlt)) {
                    if (dlt.getModifiedIndex().length > 0) {
                        return true;
                    }
                }
            }
        }
        return false;
    };
};

scwin.btn_tab_allclose_onclick = function () {//debugger;
    scwin.tabCount = tac_layout.getTabCount();
    let ret = confirm("창을 닫으면 진행 중이던 작업이 종료됩니다.\n창을 닫으시겠습니까?");
    if(ret) {
        tac_layout.deleteAllTabs();
    }
    /*
    for (let i = scwin.tabCount; i > 0; i--) {
        let ret = scwin.closeBeforePage(tac_layout.getFrame(i -1));
        if(ret) {
             tac_layout.deleteTab(i-1);
        }
    }*/
};

// 공휴일 처리 submit done
scwin.sbm_holiday_submitdone = function (e) {
    //debugger;
    $c.data.dataListFilter(dlt_holidayTmp, "saturdayYn == '0' && ddDowYn == '0'");
    dlt_holiday.setJSON(dlt_holidayTmp.getAllFilteredJSON());
    dlt_holidayTmp.removeAll();
};

// 새로고침
scwin.refresh = function() {
    try {
        let tIdx = tac_layout.getSelectedTabIndex();
        if(tIdx > -1) {
            let paramObj = tac_layout.getWindow(tIdx).$p.getParameter("paramData");
            let menuInfo = paramObj["menuInfo"];
            let menuNm = menuInfo.menuNm;
            let menuId = menuInfo.menuId;
            // let pgmId = menuInfo.refreshPid != "" ? menuInfo.refreshPid : menuInfo.pgmId;
            let pgmId = menuInfo.pgmId;
            let pgmNm = menuInfo.pgmNm;
            let src = menuInfo.src;
            let refreshPid = "";

            if(menuInfo.refreshPid) {
               refreshPid = menuInfo.refreshPid
            }

            $c.win.openMenu(menuNm,src,pgmId,paramObj,{"pgmNm" : pgmNm, "menuId" :menuId,  "openAction" : "exist", "menuCode" : refreshPid});
            // tac_layout.getWindow(tIdx).$p.reinitialize();
        }
    } catch(e) {
        console.log(e)
    }
};

// 시작 페이지 submit done
scwin.sbm_getInitPage_submitdone = async function (e) {
    let ret = e.responseJSON;
    let initFlag = false;
    try {
        if(ret.length > 0) {
            for(let idx =0; idx < ret.length; idx++ ) {
                let actPgmId = ret[idx].actPgmId;
                let actPgmScrPath = ret[idx].actPgmScrPath;
                let menuNm = ret[idx].menuNm;
                let menuId = ret[idx].menuId;
                let pgmNm = ret[idx].pgmNm;

                let prefix = "/ui";

                if(actPgmScrPath && actPgmId) {
                    prefix += actPgmScrPath.substring(0,1) !== "/" ? "/" : "";

                    if(actPgmScrPath.indexOf("/sample") > -1 || actPgmScrPath.indexOf("/pub") > -1 || actPgmScrPath.indexOf("/ui") > -1) {
                        prefix = ""
                    }
                    let src = prefix+actPgmScrPath+actPgmId;
                    src = src.replace(/.jsp/g,".xml");

                    initFlag = true;
                    await $c.win.openMenu(menuNm,src,actPgmId,null,{pgmNm : pgmNm,menuId : menuId });
                }
            }
        } else {
            if(!initFlag) {
                // 시작 화면이 등록되어 있으면 환경설정 화면 호출
                $c.win.openMenu("환경설정(Tab/m)","/ui/cm/bc/comnmgnt/usermgnt/zz_620_01_00b.xml","zz_620_01_00b.jsp",{init : "Y"});
            }
        }
    } catch(e) {
        console.log(e);
    }

};

scwin.sbm_allMenuList_submitdone = function (e) {
    // 시작화면 셋팅
    $c.sbm.execute(sbm_getInitPage);
};

// 좌측 메뉴 열고 닫기 
scwin.mtoggle_onclick = function (e) {
     $(".container").toggleClass("on")
};
